import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

function Signup() {
  const [formData, setFormData] = useState({ username: '', email: '', password: '' });
  const navigate = useNavigate();
  const handleSignup = async (e) => {
    e.preventDefault();
  try {
    // 1. Check karein URL exact yahi ho (8000 port aur /api/register)
    const response = await axios.post('http://127.0.0.1:8000/api/register', {
      username: username,
      password: password
    });

    alert("Registration Successful!");
    navigate('/login');

  } catch (err) {
    // Yahan fix hai: Pehle check karo ki response hai ya nahi
    if (err.response) {
      // Backend ne response bheja par error ke saath (e.g. 422, 400)
      console.log("Backend Error:", err.response.data);
      alert("Error: " + JSON.stringify(err.response.data.detail));
    } else if (err.request) {
      // Request bheji gayi par Backend se koi jawab nahi aaya (Network Issue)
      console.log("No Response from Backend:", err.request);
      alert("Backend server se koi jawab nahi mil raha. Kya uvicorn chalu hai?");
    } else {
      // Kuch aur galti hui setup mein
      console.log("Error Message:", err.message);
      alert("Kuch galat hua: " + err.message);
    }
  }
};


